<template>
   <div id="app" :class="typeof weather.main != 'undefined' && weather.weather[0].main == 'Rain' ? 'rain' : ''">
    <main>
      <router-link to="/"><h3>Browse more</h3></router-link>
      <div class="search-box">
        <input type="text" class="search-bar" placeholder="Search here" v-model="query" @keypress="fetchWeather">
      </div>

      <div class="weather-wrap" v-if="typeof weather.main == 'undefined'">
        <div class="location-box">
          <div class="location">
            Search for the city:
          </div>
          <div class="date">
            Simple weather app
          </div>
        </div>
      </div>

      <div class="weather-wrap" v-if="typeof weather.main != 'undefined'">
        <div class="location-box">
          <div class="location">
            {{weather.name}}, {{weather.sys.country}}
          </div>
          <div class="date">
            {{ datebuilder() }}
          </div>
        </div>

        <div class="weather-box">
          <div class="temp">{{Math.round(weather.main.temp)}}&deg;C</div>
          <div class="weather">{{ weather.weather[0].main }}</div>
        </div>
      </div>
    </main>
  </div>
</template>

<script scoped>
export default {
  name: 'App',
  data () {
    return {
      api_key:'bf7a59270cb626409f9cf3c63d2f9744',
      url_base:'https://api.openweathermap.org/data/2.5/',
      query:'',
      weather:{},
    }
  },
  methods: {
    fetchWeather (e){
      if(e.key == "Enter") {
        fetch(`${this.url_base}weather?q=${this.query}&units=metric&APPID=${this.api_key}`)
          .then(res => {
            return res.json();
        }).then(this.setResults);
      }
    },
    setResults (results){
      this.weather = results;
    },
    datebuilder(){
      let a = new Date();
      let months = ["January", "February", "March", "April", "May", "June", "July", "August", "September",
                    "October", "November", "December"];
      let days = ["Sunday","Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];

      let day = days[a.getDay()];
      let date = a.getDate();
      let month = months[a.getMonth()];
      let year = a.getFullYear();

      return `${day} ${date} ${month} ${year}`;
    }
  }
};
</script>

<style scoped>
