  background-image: url('../assets/cloudy.jpg');
  background-size: cover;
  background-position: bottom;
  transition: 0.4s;
}

#app .rain{
  background-image: url('../assets/rain.jpg');
}
main{
  min-height: 100vh;
  padding: 25px;
  background-image: linear-gradient(to bottom, rgba(0,0,0,0.25),rgba(0,0,0,0.50))
}
