  width: 100%;
  padding-bottom: 30px;
}
.search-box .search-bar{
  display: block;
  margin: 0 auto;
  width: 90%;
  padding: 15px;
  color:#313131;
  font-size: 20px;
  border:none;
  appearance:none;
  outline: none;
  background: none;
  background-color: rgba(255,255,255,0.5);
  box-shadow: 0px 0px 16px rgba(0,0,0,0.25);
  border-radius: 0px 16px 0px 16px;
  transition: 0.4s;
}
.search-box .search-bar:focus {
  box-shadow: 0px 0px 16px rgba(0,0,0,0.25);
  background-color: rgba(255,255,255,0.75);
  border-radius: 16px 0px 16px 0px;
}
.location-box .location{
  color:#fff;
  font-size: 32px;
  font-weight: 500;
  text-align: center;
  text-shadow: 1px 3px rgba(0,0,0,0.25);
}
.location-box .date{
  color:#fff;
  font-size: 20px;
  font-weight: 300;
  text-align: center;
  font-style: italic;
  padding-top: 5px;
}
.weather-box{
  text-align: center;
}
.weather-box .temp{
  display: inline-block;
